mapper.select:
  select  cast(
sum(t1.fixloss) AS DECIMAL (19, 2)
)  from app_indent t1 where to_days(t1.creat_time) = to_days(now())

SELECT DISTINCT b.merchants_name merchantsName,b.merchants_phone merchantsPhone, b.balance merchantsBalance, a.username indentName, a.phone_number indentPhone, c.`name` username, a.plan plan, a.commission_rate commissionRate, a.send_unit sendUnit, a.send_people sendPeople, a.license_plate licensePlate, d.`name` brand, a.rescue_them_fee rescueThemFee, a.responsibility, a.account account, a.insurance_company insuranceCompany,
CASE a.deal_time WHEN 1 THEN '白班' WHEN 2 THEN '夜班' ELSE '未知状态请核查' END AS dealTime,
CASE a.message_source WHEN 1 THEN '公司信息' WHEN 2 THEN '自开发' ELSE '未知状态请核查' END AS messageSource,
a.order_number orderNumber,
CASE a.state WHEN 1 THEN '新订单' WHEN 2 THEN '未到店' WHEN 3 THEN '服务中' WHEN 4 THEN '已交车' WHEN 5 THEN '未结算' WHEN 6 THEN '已完成' ELSE '未知状态请核查' END AS indentState, a.creat_time createTime, a.fixloss, a.settle_accounts settleAccounts, a.fixloss_user fixlossUser, a.settle_fours_company settleFoursCompany, a.settle_fours_company_rate settleFoursCompanyRate, a.remake remake, e.create_time outOfTime,
CASE a.send_back WHEN 1 THEN 'APP' WHEN 2 THEN '' ELSE '' END AS sendBack,
a.send_people outOfPersonnel FROM app_indent as a LEFT JOIN app_b_user as b on a.user_b_id = b.id LEFT JOIN app_user as c on a.user_id = c.id LEFT JOIN app_car_brand as d ON a.brand_id = d.id LEFT JOIN app_user_account_record as e on a.id = e.business_id AND e.source = 1 AND e.type = 4 WHERE a.creat_time BETWEEN #{beginTime} AND #{lastTime}
AND a.update_time BETWEEN #{beginUpdateTime} AND #{lastUpdateTime}
AND a.deal_time = #{dealTime}
AND a.message_source = #{messageSource}
AND a.send_people like CONCAT('%',#{sendPeople},'%')
AND a.send_unit like CONCAT('%',#{sendUnit},'%')
AND a.state = #{state}
AND a.send_back = #{sendBack}
AND a.order_number like CONCAT('%',#{orderNumber},'%')
AND a.license_plate like CONCAT('%',#{licensePlate},'%')
AND a.user_b_id = #{userBId}
AND a.account = #{account}

SELECT a.creat_time creatTime, a.license_plate licensePlate, a.send_unit sendUnit, a.send_people sendPeople, a.state state, a.fixloss fixloss, a.settle_accounts settleAccounts, a.remake remake FROM app_indent as a LEFT JOIN app_user as b ON b.id = a.user_id WHERE 1 = 1
AND b.`name` = #{username}
AND date_format(a.creat_time,'%Y-%m')= #{plan}
ORDER BY a.creat_time DESC LIMIT #{pageoffset},20

SELECT COUNT(1)
FROM app_indent as a
LEFT JOIN app_user as b ON b.id = a.user_id
WHERE 1 = 1

	AND b.`name` = #{username}



	AND  date_format(a.creat_time,'%Y-%m')= #{plan}

SELECT SUM(fixloss)
FROM app_indent as a
LEFT JOIN app_user as b ON b.id = a.user_id
WHERE 1 = 1

	AND b.`name` = #{username}



	AND  date_format(a.creat_time,'%Y-%m')= #{plan}

SELECT COUNT(1) FROM app_indent WHERE state = #{i}

	AND up_id = #{upId}


	AND user_b_id = #{userBId}

SELECT COALESCE(SUM(fixloss),0) FROM app_indent WHERE state = #{i}

	AND up_id = #{upId}


	AND user_b_id = #{userBId}

SELECT COALESCE(SUM(fixloss_user),0) FROM app_indent WHERE state = #{i}

	AND up_id = #{upId}


	AND user_b_id = #{userBId}
